interface BrandConfig {
  id: string;
  name: string;
  logo: string;
  hotline: string;
  website: string;
  color: string;
  description?: string;
  fontFamily?: string;
  logoPosition?: 'left' | 'right';
}

const createBrandTemplate = (config: BrandConfig): Template => ({
  id: config.id,
  name: config.name,
  description: config.description || '',
  themeColor: config.color,
  header: () => {
    const fontImport = config.fontFamily 
      ? `@import url('https://fonts.googleapis.com/css2?family=${config.fontFamily.replace(/\s/g, '+')}:wght@400;500;600;700&display=swap');`
      : '';
    const fontFamily = config.fontFamily ? `font-family: '${config.fontFamily}', sans-serif;` : '';
    const isLogoRight = config.logoPosition === 'right';

    return `
    <style>
      ${fontImport}
      .brand-container { ${fontFamily} }
      .prose a { color: ${config.color} !important; text-decoration: none; font-weight: 600; }
      .prose a:hover { text-decoration: underline; }
    </style>
    <div class="brand-container">
      <div class="flex items-center justify-between border-b-[3px] py-4 mb-8 ${isLogoRight ? 'flex-row-reverse' : ''}" style="border-color: ${config.color}">
        <div class="flex items-center">
          ${config.logo}
        </div>
        <div class="${isLogoRight ? 'text-left' : 'text-right'}">
          <div class="flex items-center ${isLogoRight ? 'justify-start' : 'justify-start'} gap-2 mb-1">
            <a href="tel:${config.hotline.replace(/\s/g, '')}" class="flex items-center gap-2" style="color: inherit; text-decoration: none;">            
              <span class="w-5 h-5 flex items-center justify-center">${getPhoneIcon(config.color)}</span>
              <span class="text-sm font-medium">${config.hotline}</span>
            </a>
          </div>
          <div class="flex items-center ${isLogoRight ? 'justify-start' : 'justify-start'} gap-2">
            <a href="${config.website}" target="_blank" class="flex items-center gap-2" style="color: inherit; text-decoration: none;">            
              <span class="w-5 h-5 flex items-center justify-center">${getWebIcon(config.color)}</span>
              <span class="text-sm font-medium">${config.website.replace('https://', '').replace('/', '')}</span>
            </a>
          </div>
        </div>
      </div>
    </div>
  `},
  footer: () => ``,
  containerClass: 'max-w-6xl mx-auto py-10 sm:py-16 px-4 sm:px-8 bg-white'
});

